from fastapi import FastAPI
from fastapi.testclient import TestClient
from pydantic import BaseModel

app = FastAPI()

class Task(BaseModel):
    title: str
    done: bool = False

tasks: dict[int, dict] = {}
counter = 0

@app.get("/tasks/", tags=["tasks"])
def list_tasks():
    """List all tasks."""
    return list(tasks.values())

@app.post("/tasks/", status_code=201, tags=["tasks"])
def create_task(task: Task):
    """Create a new task."""
    global counter
    counter += 1
    record = {"id": counter, **task.model_dump()}
    tasks[counter] = record
    return record

@app.get("/tasks/{task_id}", tags=["tasks"])
def get_task(task_id: int):
    """Get a specific task."""
    return tasks.get(task_id, {"error": "not found"})

@app.put("/tasks/{task_id}", tags=["tasks"])
def replace_task(task_id: int, task: Task):
    """Replace an entire task."""
    tasks[task_id] = {"id": task_id, **task.model_dump()}
    return tasks[task_id]

@app.patch("/tasks/{task_id}", tags=["tasks"])
def update_task(task_id: int, task: Task):
    """Partially update a task."""
    if task_id in tasks:
        stored = tasks[task_id]
        stored.update(task.model_dump(exclude_unset=True))
        return stored
    return {"error": "not found"}

@app.delete("/tasks/{task_id}", status_code=204, tags=["tasks"])
def delete_task(task_id: int):
    """Delete a task."""
    tasks.pop(task_id, None)

